import React, { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import Cookie from "cookie-universal";

import "../../Styles/Dashboard.css";


   // Custom Hook

// Components
import UserHeader from "./Users/components/UserHeader";
import DashboardNav from "./components/DashboardNav";
import UserStatsCards from "./Users/components/UserStatsCards";
import UsersTable from "./Users/components/UsersTable";
import UserModal from "./Users/components/UserModal";

export default function UserManagement() {
  const navigate = useNavigate();
  const cookie = Cookie();

  const { users, loading, handleDelete, handleSubmit } = useUsers();

  const [showModal, setShowModal] = useState(false);
  const [editMode, setEditMode] = useState(false);
  const [currentUser, setCurrentUser] = useState(null);

  useEffect(() => {
    const user = cookie.get("educational-user");
    if (!user) {
      navigate("/login");
      return;
    }

    let userData;
    if (typeof user === "string") {
      userData = JSON.parse(user);
    } else {
      userData = user;
    }

    if (userData.role !== "admin") {
      alert("غير مصرح لك بالوصول لهذه الصفحة");
      navigate("/");
    }
  }, []);

  function openAddModal() {
    setEditMode(false);
    setCurrentUser(null);
    setShowModal(true);
  }

  function openEditModal(user) {
    setEditMode(true);
    setCurrentUser(user);
    setShowModal(true);
  }

  if (loading) {
    return (
      <div className="loading-container">
        <div className="spinner"></div>
        <p>جاري التحميل...</p>
      </div>
    );
  }

  return (
    <div className="dashboard-page">
      <UserHeader onAddClick={openAddModal} />

      <div className="dashboard-content">
        <div className="container">
          <DashboardNav />
          <UserStatsCards users={users} />
          <UsersTable
            users={users}
            onEdit={openEditModal}
            onDelete={handleDelete}
          />
        </div>
      </div>

      <UserModal
        show={showModal}
        onClose={() => setShowModal(false)}
        onSubmit={handleSubmit}
        editMode={editMode}
        currentUser={currentUser}
      />
    </div>
  );
}
